using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

// Build test data
var words = new[] {
    "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
    "performance", "benchmarking", "is", "important", "for", "understanding",
    "how", "code", "behaves", "under", "different", "runtime", "versions",
    "and", "configurations", "that", "may", "affect", "throughput", "latency",
    "memory", "allocation", "patterns", "in", "production", "workloads"
};
var rng = new Random(42);
var parts = new string[5000];
for (int i = 0; i < parts.Length; i++)
    parts[i] = words[rng.Next(words.Length)];
var analyzer = new TextAnalyzer(string.Join(' ', parts));

Console.WriteLine($"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}");
Console.WriteLine($"Words: {analyzer.WordCount}");
Console.WriteLine();

const int warmupIterations = 500;
const int measuredIterations = 5000;

Benchmark("AverageWordLength", () => analyzer.AverageWordLength());
Benchmark("WordLengthHistogram", () => analyzer.WordLengthHistogram());
Benchmark("UniqueWordCount", () => analyzer.UniqueWordCount());

static void Benchmark(string name, Func<object?> action)
{
    // Warmup
    for (int i = 0; i < warmupIterations; i++)
        action();

    // Collect multiple rounds for statistics
    const int rounds = 5;
    double[] roundNs = new double[rounds];
    int itersPerRound = measuredIterations / rounds;

    for (int r = 0; r < rounds; r++)
    {
        GC.Collect();
        GC.WaitForPendingFinalizers();
        GC.Collect();

        long memBefore = GC.GetTotalAllocatedBytes(precise: true);
        var sw = Stopwatch.StartNew();
        for (int i = 0; i < itersPerRound; i++)
            action();
        sw.Stop();
        long memAfter = GC.GetTotalAllocatedBytes(precise: true);

        roundNs[r] = (double)sw.ElapsedTicks / Stopwatch.Frequency * 1e9 / itersPerRound;

        if (r == rounds - 1)
        {
            double allocPerOp = (double)(memAfter - memBefore) / itersPerRound;
            double mean = roundNs.Average();
            double stddev = Math.Sqrt(roundNs.Select(x => (x - mean) * (x - mean)).Sum() / rounds);
            Console.WriteLine($"{name,-25} {mean,10:F1} ns ± {stddev,8:F1} ns  | alloc: {allocPerOp,8:F0} B/op");
        }
    }
}

